import React, { useState, useEffect, useContext, useMemo } from 'react';
import { AuthContext } from '../context/AuthContext';
import api from '../api/axiosConfig';
import { Activity, Zap, TrendingUp, TrendingDown, ChevronLeft, ChevronRight, Box, BarChart2 } from 'lucide-react';

const LiveMarketPage = () => {
    const { token } = useContext(AuthContext);

    // --- 1. STATE MANAGEMENT ---
    const [history, setHistory] = useState([]);
    const [currentIndex, setCurrentIndex] = useState(0);
    const [stocks, setStocks] = useState([]);
    const [isConnected, setIsConnected] = useState(false);
    
    // Graph State: Stores last 20 points of "Market Heat"
    const [graphData, setGraphData] = useState(Array(20).fill(50));

    // --- 2. DATA INITIALIZATION ---
    useEffect(() => {
        const fetchVault = async () => {
            try {
                const res = await api.get('/portfolio/history');
                setHistory(res.data);
                if (res.data.length > 0) {
                    initializeStocks(res.data[0].holdings);
                }
            } catch (err) {
                console.error("VAULT_SYNC_ERROR");
            }
        };
        fetchVault();
    }, []);

    const initializeStocks = (holdingsData) => {
        try {
            let tickers = typeof holdingsData === 'string' ? JSON.parse(holdingsData) : holdingsData;
            if (typeof tickers === 'string') tickers = JSON.parse(tickers);
            
            const initialSet = tickers.map(t => ({
                ticker: t,
                price: Math.floor(Math.random() * 2000) + 500,
                change: 0
            }));
            setStocks(initialSet);
        } catch (e) { setStocks([]); }
    };

    // --- 3. LIVE WEBSOCKET & GRAPH LOGIC ---
    useEffect(() => {
        if (!token) return;
        const ws = new WebSocket(`ws://localhost:8000/ws/pulse?token=${token}`);

        ws.onopen = () => setIsConnected(true);
        ws.onmessage = (event) => {
            // Update Stocks
            setStocks(prev => prev.map(s => {
                const move = (Math.random() - 0.5) * 10;
                return { ...s, price: +(s.price + move).toFixed(2), change: +move.toFixed(2) };
            }));

            // Update Graph (Simulate Index Movement)
            setGraphData(prev => {
                const lastVal = prev[prev.length - 1];
                const nextVal = Math.max(10, Math.min(90, lastVal + (Math.random() - 0.5) * 15));
                return [...prev.slice(1), nextVal];
            });
        };
        ws.onclose = () => setIsConnected(false);
        return () => ws.close();
    }, [token, currentIndex]);

    // --- 4. NAVIGATION ---
    const navigate = (direction) => {
        let newIndex = currentIndex + direction;
        if (newIndex >= 0 && newIndex < history.length) {
            setCurrentIndex(newIndex);
            initializeStocks(history[newIndex].holdings);
        }
    };

    // SVG Graph Path Generator
    const points = useMemo(() => {
        return graphData.map((val, i) => `${i * 25},${100 - val}`).join(' ');
    }, [graphData]);

    const activeNode = history[currentIndex];

    return (
        <div style={containerStyle}>
            {/* ── Navigation Header ── */}
            <div style={navHeader}>
                <button 
                    onClick={() => navigate(1)} 
                    disabled={currentIndex === history.length - 1}
                    style={navBtn(currentIndex === history.length - 1)}
                >
                    <ChevronLeft size={20}/> PREV_NODE
                </button>

                <div style={activeInfo}>
                    <Box size={16} color="var(--accent-primary)" />
                    <span style={nodeIdText}>
                        {activeNode ? `TERMINAL_STREAM: ${activeNode.goal.substring(0, 35)}...` : 'AWAITING_UPLINK...'}
                    </span>
                    <span style={indexText}>{currentIndex + 1} / {history.length}</span>
                </div>

                <button 
                    onClick={() => navigate(-1)} 
                    disabled={currentIndex === 0}
                    style={navBtn(currentIndex === 0)}
                >
                    NEXT_NODE <ChevronRight size={20}/>
                </button>
            </div>

            {/* ── Real-Time Market Graph ── */}
            <div style={graphContainer}>
                <div style={graphHeader}>
                    <BarChart2 size={16} color="var(--accent-primary)" />
                    <span style={graphTitle}>GLOBAL_MARKET_VOLATILITY_INDEX</span>
                    <div style={pulseDot(isConnected)} />
                </div>
                <svg viewBox="0 0 475 100" style={svgStyle}>
                    <polyline
                        fill="none"
                        stroke="var(--accent-primary)"
                        strokeWidth="2"
                        strokeLinejoin="round"
                        points={points}
                        style={{ transition: 'all 0.5s ease-in-out' }}
                    />
                </svg>
            </div>

            {/* ── Live Ticker Grid ── */}
            <div style={gridStyle}>
                {stocks.map((stock, i) => (
                    <div key={i} style={stockCardStyle(stock.change > 0)}>
                        <div style={cardTop}>
                            <span style={tickerName}>{stock.ticker}</span>
                            <Zap size={14} color={stock.change > 0 ? "#10b981" : "#ef4444"} />
                        </div>
                        <div style={priceStyle}>₹{stock.price.toLocaleString()}</div>
                        <div style={changeStyle(stock.change > 0)}>
                            {stock.change > 0 ? <TrendingUp size={14}/> : <TrendingDown size={14}/>}
                            {stock.change > 0 ? '+' : ''}{stock.change}%
                        </div>
                    </div>
                ))}
                {stocks.length === 0 && <div style={emptyState}>NO_ACTIVE_TICKERS_IN_NODE</div>}
            </div>
        </div>
    );
};

/* --- Terminal UI Styles --- */
const containerStyle = { padding: '2rem', maxWidth: '1200px', margin: '0 auto', display: 'flex', flexDirection: 'column', gap: '2rem' };
const navHeader = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', background: 'var(--surface-glass)', padding: '1rem 2rem', borderRadius: '15px', border: '1px solid var(--surface-border)', backdropFilter: 'blur(10px)' };
const activeInfo = { display: 'flex', alignItems: 'center', gap: '12px' };
const nodeIdText = { fontSize: '0.75rem', fontWeight: 800, color: 'var(--text-primary)', fontFamily: 'monospace', letterSpacing: '0.05em' };
const indexText = { fontSize: '0.6rem', color: 'var(--accent-primary)', background: 'rgba(16,185,129,0.1)', padding: '3px 10px', borderRadius: '4px', fontWeight: 900, border: '1px solid rgba(16,185,129,0.2)' };

const navBtn = (disabled) => ({
    display: 'flex', alignItems: 'center', gap: '5px', background: 'none', border: 'none',
    color: disabled ? 'var(--text-muted)' : 'var(--accent-primary)', cursor: disabled ? 'default' : 'pointer',
    fontSize: '0.7rem', fontWeight: 800, fontFamily: 'monospace', opacity: disabled ? 0.3 : 1
});

const graphContainer = { background: '#0a0b0e', borderRadius: '20px', border: '1px solid var(--surface-border)', padding: '1.5rem', position: 'relative', overflow: 'hidden' };
const graphHeader = { display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '1rem' };
const graphTitle = { fontSize: '0.65rem', fontWeight: 800, color: 'var(--text-muted)', letterSpacing: '0.2em' };
const svgStyle = { width: '100%', height: '120px', overflow: 'visible' };
const pulseDot = (active) => ({ width: '8px', height: '8px', borderRadius: '50%', background: active ? '#10b981' : '#ef4444', boxShadow: active ? '0 0 10px #10b981' : 'none' });

const gridStyle = { display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))', gap: '1.5rem' };
const stockCardStyle = (up) => ({
    padding: '1.8rem', background: 'var(--surface-glass)', border: '1px solid var(--surface-border)',
    borderRadius: '24px', borderLeft: `5px solid ${up ? '#10b981' : '#ef4444'}`, transition: 'all 0.3s ease'
});

const cardTop = { display: 'flex', justifyContent: 'space-between', marginBottom: '1rem' };
const tickerName = { fontSize: '0.75rem', color: 'var(--text-muted)', fontWeight: 800, letterSpacing: '0.1em' };
const priceStyle = { fontSize: '2rem', fontWeight: 900, color: 'var(--text-primary)', fontFamily: 'monospace' };
const changeStyle = (up) => ({ fontSize: '0.85rem', color: up ? '#10b981' : '#ef4444', display: 'flex', alignItems: 'center', gap: '6px', marginTop: '8px', fontWeight: 800 });
const emptyState = { gridColumn: '1/-1', textAlign: 'center', padding: '5rem', color: 'var(--text-muted)', fontFamily: 'monospace', border: '1px dashed var(--surface-border)', borderRadius: '24px' };

export default LiveMarketPage;
